impl Solution { pub fn reorder_list(black_h: &mut Option<Box<ListNode>>) { if black_h.is_none() { return; } let mut black_v = vec![]; let mut black_c = black_h.take(); while let Some(mut black_n) = black_c { black_c = black_n.next.take(); black_v.push(Some(black_n)); } let (mut black_i, mut black_j, mut black_p) = (0, black_v.len() as i32 - 1, black_h); while black_i <= black_j { *black_p = black_v[black_i as usize].take(); black_p = &mut black_p.as_mut().unwrap().next; if black_i < black_j { *black_p = black_v[black_j as usize].take(); black_p = &mut black_p.as_mut().unwrap().next; } black_i += 1; black_j -= 1; } } }